function waveF = fReadNIWaveHdf5(fNam,axisNmb)%% function read HDF5 (NI Waveform)%% waveF = fReadNIWaveHdf5(fNam)%% waveF: waveform [V]%% fNam: full path to hdf5 file% axisNmb: axis number%%% Written by Kei Nakamura%% 2020/3/20: created% %% main bodydatTree = ['/wfm_group0/axes/axis',num2str(axisNmb)];   % data treewaveF = h5read(fNam,[datTree,'/data_vector/data']);    % integar datasclD1 = h5read(fNam,[datTree,'/scale_coef']); % scaleswaveF = double(waveF)*sclD1(2)+sclD1(1); % convert to [V]%% legasy part% h5disp(fNameI,'/wfm_group0/axes/axis0'); % to see file info% ictD1 = h5read(fNameI,'/wfm_group0/axes/axis1/data_vector/data');% sclD1 = h5read(fNameI,'/wfm_group0/axes/axis1/scale_coef');% ictD1 = double(ictD1)*sclD1(2)+sclD1(1); % convert to [V]% ictD1 = 0.5*ictRng(1)*double(ictD1)/(2^15);   % t-ict y-axis info% ictAx1 = h5info(fNameI,'/wfm_group0/axes/axis1');
